content.problemStatement:
Given the following code, what will be the output when the program is executed?

```cpp
#include 
using namespace std;

// Overloaded function to add two integers and return an integer
int add(int a, int b) {
    return a + b;
}

// Overloaded function to add two doubles and return a double
double add(double a, double b) {
    return a + b + 0.5;
}

int main() {
    int intResult = add(3, 4);         // Calls add(int, int)
    double doubleResult = add(3.5, 4.5);  // Calls add(double, double)

    cout << "Sum of integers: " << intResult << endl;
    cout << "Sum of doubles: " << doubleResult << endl;

    return 0;
}
```

